commands.cmd:
raw=$(journalctl -u cron --since "2024-01-01 12:00:00" --until "2024-01-02 12:00:00" -o json --no-pager -q 2>/dev/null) || { echo "journalctl failed" >&2; exit 1; }
now_s=$(date +%s)
printf '%s' "$raw" | jq -r 'select(.MESSAGE | test("\\) CMD \\(")) | "\(.__REALTIME_TIMESTAMP) \(.MESSAGE)"' \
  | awk -v now="$now_s" '
    {
      ts_us=$1
      cmd=$0
      sub(/^[0-9]+ /, "", cmd)
      sub(/.* CMD \(/, "", cmd)
      sub(/\)[[:space:]]*$/, "", cmd)
      last[cmd]=ts_us
    }
    END{
      for (c in last) {
        age=int(now - last[c]/1000000)
        printf "%s\t%d\n", c, age
      }
    }' \
  | sort \
  | awk -F'\t' '
    BEGIN{ printf "{\"results\":["; sep="" }
    {
      cmd=$1
      gsub(/\\/, "\\\\", cmd); gsub(/"/, "\\\"", cmd)
      printf "%s{\"command\":\"%s\",\"last_run_age_sec\":%d}", sep, cmd, $2
      sep=","
    }
    END{ printf "]}" }' || { echo "awk/sort failed" >&2; exit 1; }
